    <div>
        <div style="clear:both;">
            <p><span style="font-family:'Helvetica Neue';">&nbsp;</span></p>
        </div>
        <p style="text-align:center; widows:0; orphans:0;"><strong><u><span style="font-family:'Libre Baskerville';">CONTRACT OF LOAN</span></u></strong></p>
        <p style="text-align:center; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:center; line-height:150%; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">KNOW ALL MEN BY THESE PRESENTS:</span></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:justify; line-height:150%; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span><span style="font-family:'Libre Baskerville';">This Contract of Loan is made, executed, and entered into this 26 day of MAY, 2026, by and between:&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; line-height:150%; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">INDO-PACIFIC LENDING CORPORATION</span></strong><span style="font-family:'Libre Baskerville';">, a corporation duly organized and existing under and in accordance with the laws of the Republic of the Philippines, with office and principal place of business at H. Alquizola Street, Poblacion, Barili, Cebu, Philippines, herein represented by Raven Wyndell C. Ricaplaza, and hereinafter referred to as the&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">&ldquo;LENDER&rdquo;</span></strong><span style="font-family:'Libre Baskerville';">;</span></p>
        <p style="text-align:justify; line-height:150%; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:center; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">-AND-</span></p>
        <p style="text-align:center; line-height:150%; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">MRS. ANNABELLE S. RELLON, </span></strong><span style="font-family:'Libre Baskerville';">of legal age, married, Filipino, and residents of SIBONGA, Cebu, Philippines, hereinafter collectively referred to as the&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">&ldquo;PRINCIPAL BORROWER&rdquo;</span></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></strong><strong><span style="font-family:'Libre Baskerville';">JHAIZE KLENT S RELLON, ALMA ANN A. ROSALES, JUGIELYN EBO </span></strong><span style="font-family:'Libre Baskerville';">of legal age, married, Filipino, and with residence at ARGAO Cebu, Philippines, hereinafter referred to as the &ldquo;</span><strong><span style="font-family:'Libre Baskerville';">CO-BORROWER/CO-DEBTOR&rdquo;</span></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:justify; line-height:150%; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:center; line-height:150%; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">WITNESSETH THAT:</span></strong></p>
        <p style="text-align:center; line-height:150%; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">FOR VALUE RECEIVED</span></strong><span style="font-family:'Libre Baskerville';">, the&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">PRINCIPAL BORROWER AND CO-BORROWER</span></strong><span style="font-family:'Libre Baskerville';">, hereby jointly and severally promise/s to pay to the LENDER or order, the principal sum of&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong><strong><span style="font-family:'Libre Baskerville';">FIVE HUNDRED FIFTY THOUSAND PESOS (PHP. 550,000), </span></strong><span style="font-family:'Libre Baskerville';">together with the&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">ONE POINT FIVE PERCENT (1.5%) service charge </span></strong><span style="font-family:'Libre Baskerville';">on the principal amount and an interest rate of&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">ONE POINT FOUR TWO EIGHT PERCENT (1.428%) PER MONTH OR SEVENTEEN POINT ONE THREE SIX PERCENT (17.136%) PER ANNUM</span></strong><span style="font-family:'Libre Baskerville';">, subject further to the terms and conditions set forth below:</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:center; widows:0; orphans:0;"><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></p>
        <p style="text-align:center; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">ADDITIONAL TERMS AND CONDITIONS</span></strong></p>
        <p style="text-align:center; line-height:150%; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:53.27pt; text-align:justify; widows:0; orphans:0; padding-left:22.73pt; font-family:'Libre Baskerville'; font-weight:bold;">SERVICE CHARGE, INTEREST AND REPAYMENT TERMS: <span style="font-weight:normal;">The Service Charge of ONE POINT FIVE&nbsp;</span><em>percent (1.5</em><span style="font-weight:normal;">%) of the principal amount shall be deducted by the LENDER from the proceeds of FIVE HUNDRED FIFTY THOUSAND PESOS (PHP. 550,000.00).</span> <span style="font-weight:normal;">The principal amount of this Loan together with the interest rate of&nbsp;</span>ONE POINT FOUR TWO EIGHT PERCENT (1.482%) PER MONTH<span style="font-weight:normal;">&nbsp;and all other charges, cost, expenses, shall be paid according to the schedule of payments agreed by the PRINCIPAL BORROWER, CO-BORROWER and the LENDER in the document attached and made an integral part hereof as Annex&nbsp;</span>&ldquo;A<span style="font-weight:normal;">&rdquo;.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol start="2" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:58.42pt; text-align:justify; widows:0; orphans:0; padding-left:17.58pt; font-family:'Libre Baskerville'; font-weight:bold;">PREPAYMENT/ PRE-TERM FEE<span style="font-weight:normal;">: The PRINCIPAL BORROWER AND CO-BORROWER may accelerate the payment of all or any part of the principal amount of this Loan, together with the accrued and unpaid interest, provided that the PRINCIPAL BORROWER AND CO-BORROWER shall inform the LENDER through a written notice Five (5) days before the prepayment and personally request a copy of his/her Statement of Account in person at the LENDER&rsquo;S principal place of business. Failure to notify the LENDER in writing or request a copy of his/her Statement of Account in person shall allow the latter to deny their request for prepayment.&nbsp;</span>In case the PRINCIPAL BORROWER AND CO-BORROWER choose to prepay the principal amount and the accrued interest, the LENDER shall charge a Pre-payment/Pre-term Fee of 2% of the total outstanding principal obligation.</li>
        </ol>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol start="3" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:63.56pt; text-align:justify; widows:0; orphans:0; padding-left:12.44pt; font-family:'Libre Baskerville'; font-weight:bold;">CONDITION FOR RENEWAL: <span style="font-weight:normal;">As a rule, any application for renewal is subject to review and sole discretion of the LENDER and provided that the previous loan is fully paid.&nbsp;</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:72pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">However, if renewal before the full payment of a previous loan is considered, such shall be allowed only if the current loan account is up-to-date. Upon renewal of the loan, the outstanding balance of the previous loan together with the interest, charges, and penalties, if any, shall be deducted from the proceeds of the new loan.</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol start="4" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:62.93pt; text-align:justify; widows:0; orphans:0; padding-left:13.07pt; font-family:'Libre Baskerville'; font-weight:bold;">SECURITY: <span style="font-weight:normal;">As security for this Loan, the PRINCIPAL BORROWER shall deliver, turn-over possession, and assign to the LENDER all rights, title, and interest in his/her/their&nbsp;</span>SAVINGS/CURRENT ACCOUNTS <span style="font-weight:normal;">with the Development Bank of the Philippines (DBP) with Account Number: 7355594079together with his/her/their Automated Teller Machine (</span><em><span style="font-weight:normal;">ATM</span></em><span style="font-weight:normal;">) Card bearing No. 5177145868, and his/her Unified Multipurpose Identification Card bearing No. _______________ as secondary security.&nbsp;</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER hereby authorizes the LENDER to withdraw from his/her/their account/s the amounts and in such frequencies and intervals as indicated in the schedule of payments (Annex &ldquo;A&rdquo;).</span><span style="font-family:'Libre Baskerville';">&nbsp;&nbsp;</span><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER shall also provide the LENDER the necessary Personal Identification Number (PIN) of their respective ATM Cards.</span></p>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER shall not cause the cancellation or deactivation of the afore-described ATM Card and UMID Card nor apply, acquire, and/or obtain a new or replacement ATM Card and UMID Card until he/she/they has/have obtained from the LENDER the necessary release of his/her/their obligation after full payment of the principal obligation together with any accrued interest.</span></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER undertake not to enroll, access, or activate online banking services in relation to the ATM Card and/or Bank Account assigned, delivered, and submitted in favor of the LENDER as security.&nbsp;</span><strong><u><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER shall not conduct any electronic or mobile banking transactions, including but not limited to fund transfers and withdrawal overrides relative to the aforementioned security. Any act by the PRINCIPAL BORROWER enabling or facilitating online access of the said ATM Cards or account, or interfering with LENDER&rsquo;S ability to monitor, transact, or collect any payment therefrom shall constitute as material breach of this contract and is a ground for Default.</span></u></strong></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">In cases where the aforementioned ATM Card and/or UMID card is cancelled, deactivated or in way cannot be transacted, the PRINCIPAL BORROWER shall automatically be barred from acquiring any new and future loans and cash advances from the LENDER without prejudice to the exercise of the LENDER&rsquo;s rights under Paragraph V of this Contract of Loan and all other rights granted to the LENDER by law. Provided, the PRINCIPAL BORROWER may seek reconsideration within Five (5) Calendar days from receipt of any notice or Demand Letter to submit their written Letter for Reconsideration and Notarized Affidavit of Undertaking declaring that they have acquired a new ATM Card/UMID without knowledge of the LENDER and undertake to turn-over the reacquired ATM Card/UMID Card within the Five (5) Calendar days.</span></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">In the event that the bank account provided by the PRINCIPAL BORROWER as security for the Loan is closed, suspended, restricted, frozen, rendered inactive, or otherwise becomes unavailable for any reason which includes retirement from employment or service, the Borrower shall immediately notify the Lender in writing and, within&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">THREE (3) CALENDAR DAYS</span></strong><span style="font-family:'Libre Baskerville';">&nbsp;from such occurrence, provide and maintain another valid and active bank account acceptable to the LENDER as replacement security for the Loan. The PRINCIPAL BORROWER further undertakes to execute and submit all documents necessary to effect such replacement. Failure to comply with this obligation shall constitute a default under this Agreement and shall entitle the LENDER to exercise all rights and remedies available under this Agreement and applicable law.</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol start="5" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:57.78pt; text-align:justify; widows:0; orphans:0; padding-left:18.22pt; font-family:'Libre Baskerville'; font-weight:bold;">AUTO DEBIT AGREEMENT: <span style="font-weight:normal;">The PRINCIPAL BORROWERS hereby authorizes the LENDER to automatically debit from the PRINCIPAL BORROWERS designated security under Paragraph IV of this Agreement the amount due under Annex &ldquo;A&rdquo; and any and all provisions of this Contact of Loan which includes but not limited to the interest payment, penalties, and other charges on each due date without need of any demand. Amounts debited from the PRINCIPAL BORROWER enrolled account/s will be automatically applied to the payment of the amount due to the</span><span style="font-weight:normal;">&nbsp;&nbsp;</span><span style="font-weight:normal;">PRINCIPAL BORROWER.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER undertake to maintain sufficient funds in the enrolled account to cover all amount due therein. In the event of insufficiency of funds in the enrolled account, the PRINCIPAL BORROWER shall be liable for a penalty fee of ONE THOUSAND PESOS (Php. 1,000.00) per attempt without regard to the other fees and charges which maybe imposed under this Contract of Loan and the law.&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">The Auto Debit Agreement shall be in force until the principal and the interest together with any fees and charges are fully paid.&nbsp;</span><strong><u><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER shall not be allowed to revoke any Auto Debit Agreement duly approved by their respective banks unless full payment is made. Any revocation without the consent of the LENDER shall constitute as breach of contract.</span></u></strong></p>
        <p style="margin-left:76.25pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER also hereby waive their rights under the Secrecy of Bank Deposits Law under Republic Act No. 1405 in connection with any information which maybe disclosed to the LENDER for the implementation of the ADA.</span></p>
        <p style="widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="6" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:62.93pt; text-align:justify; widows:0; orphans:0; padding-left:13.07pt; font-family:'Libre Baskerville'; font-weight:bold;">DEFAULT AND BREACH: <span style="font-weight:normal;">The PRINCIPAL BORROWER shall be in default upon the occurrence of any of the following events:</span></li>
        </ol>
        <p style="margin-left:94pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:90.83pt; text-align:justify; widows:0; orphans:0; padding-left:3.17pt; font-family:'Libre Baskerville';">Any or all of the PRINCIPAL BORROWER become insolvent or seeks an order of relief under the Financial Rehabilitation and Insolvency Act of 2010 or subsequent laws governing rehabilitation and insolvency or shall commit or permit any act of bankruptcy under applicable law;</li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="2" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:92.03pt; text-align:justify; widows:0; orphans:0; padding-left:1.97pt; font-family:'Libre Baskerville';">Any or all of the PRINCIPAL BORROWER is/are unable to pay their obligation on their respective due date/s under the terms and condition of this Contract of Loan;</li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="3" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:90.61pt; text-align:justify; widows:0; orphans:0; padding-left:3.39pt; font-family:'Libre Baskerville';">any of PRINCIPAL BORROWER representations and warranties as specified hereunder shall prove false in any material respect when made;</li>
        </ol>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="4" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:92.28pt; text-align:justify; widows:0; orphans:0; padding-left:1.72pt; font-family:'Libre Baskerville';">Any violation to Article IV of this Contract of Loan.</li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="5" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:91.06pt; text-align:justify; widows:0; orphans:0; padding-left:2.94pt; font-family:'Libre Baskerville';">Any violation to Article V of this Contract of Loan.</li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="6" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:89.12pt; text-align:justify; widows:0; orphans:0; padding-left:4.88pt; font-family:'Libre Baskerville';">Any act, omission, or conduct by the PRINCIPAL BORROWER that directly, or indirectly frustrates, obstructs, or hinders the implementation, performance, or enforcement of any of the provisions of this Contract of Loan shall be deemed a material breach of this Contract. This includes but not limited to, providing false or misleading information against the LENDER, refusing to cooperate in good faith, concealing material facts which may affect the interest of the LENDER, transferring assets to avoid payment, or deliberately avoiding communication related to this loan.</li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="7" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:91.37pt; text-align:justify; widows:0; orphans:0; padding-left:2.63pt; font-family:'Libre Baskerville';">When PRINCIPAL BORROWER engage in conduct that, in the reasonable judgment of the LENDER, causes substantial reputational harm to the LENDER, and such harm cannot be adequately addressed or cured within ten (10) days of written notice. For the purposes of this clause, &apos;substantial reputational harm&apos; includes, but is not limited to, actions that damage the LENDER&apos;s standing, bring the LENDER into disrepute, attract adverse publicity, or harm public confidence in the LENDER.&nbsp;</li>
        </ol>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="5" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:57.78pt; text-align:justify; widows:0; orphans:0; padding-left:18.22pt; font-family:'Libre Baskerville'; font-weight:bold;">CONSEQUENCES OF DEFAULT AND/OR BREACH: <span style="font-weight:normal;">Upon the occurrence of an event of default, the LENDER shall have the option to exercise any of the following remedies, alternatively or cumulatively at its discretion, in conjunction with or separately from any other right or remedy granted hereunder or under the law, without need for any legal or judicial action or order, to enforce payment of this Contract:</span><span style="font-weight:normal;">&nbsp;&nbsp;</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:91.01pt; text-align:justify; widows:0; orphans:0; padding-left:2.99pt; font-family:'Libre Baskerville'; font-weight:bold;"><span style="font-weight:normal;">The principal obligation as well as the interest, costs, additional charges, expenses, if any, shall be immediately due and demandable;</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="2" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:92.21pt; text-align:justify; widows:0; orphans:0; padding-left:1.79pt; font-family:'Libre Baskerville'; font-weight:bold;"><span style="font-weight:normal;">PRINCIPAL BORROWER AND CO-BORROWER shall pay the LENDER a penalty of TEN THOUSAND PESOS (PhP10,000.00) or at the rate of two percent (2%) per month, whichever is higher,</span><span style="font-weight:normal;">&nbsp;&nbsp;</span><span style="font-weight:normal;">from the date of notice of default or the expiration of any grace period granted in the written demand, at the election of the LENDER, until the BORROWER pays the full amount due (principal amortization or accrued interest or both as the case may be). The imposition and payment of the penalty shall not however be construed as a waiver on the part of the LENDER to file appropriate CIVIL, CRIMINAL, or ADMINISTRATIVE ACTIONS against any or all of the BORROWERS which includes complaints with the Department of Education, Commission on Higher Education and/or the Civil Service Commission;</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="3" style="margin:0pt; padding-left:0pt; list-style-type:lower-latin;">
            <li style="margin-left:90.89pt; text-align:justify; widows:0; orphans:0; padding-left:3.11pt; font-family:'Libre Baskerville'; font-weight:bold;"><span style="font-weight:normal;">LENDER may cause the publication and posting of notice to the public in local newspapers and newspapers of general circulation relevant to BORROWERS&rsquo; acts or transgressions and share the same with other lenders, credit reporting agencies and duly accredited outsourced entities.&nbsp;</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="6" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:61.34pt; text-align:justify; padding-left:14.66pt; font-weight:bold;">GRACE PERIOD ON PENALTIES AND SURCHARGES<span style="font-weight:normal;">:</span><span style="font-family:'Libre Baskerville'; font-weight:normal;">The Principal Borrower and Co-Borrower shall be allowed a grace period on penalties and surcharges of&nbsp;</span><span style="font-family:'Libre Baskerville';">THREE HUNDRED SIXTY-FIVE (365)&nbsp;</span><span style="font-family:'Libre Baskerville'; font-weight:normal;">calendar days from the due date for the payment of any installment or obligation under this Agreement. Payments made within the grace period shall not be subject to penalties or late charges, provided that interest shall continue to accrue on the outstanding balance. In the event that payment is not made within the grace period, the Principal Borrower and Co-Borrower shall automatically be made liable for penalties and surcharges without need of prior demand or notice and without regard to the Lender&rsquo;s rights to exercise all remedies available under this Agreement and applicable law.</span></li>
        </ol>
        <p><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="7" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:68.08pt; text-align:justify; widows:0; orphans:0; padding-left:7.92pt; font-family:'Libre Baskerville'; font-weight:bold;">NATURE OF LIABILITY<span style="font-weight:normal;">:&nbsp;</span><u>The PRINCIPAL BORROWER, together with the CO-BORROWER, hereby agrees, binds, covenants, themselves jointly and severally (in solidum) to the LENDER for the full and faithful payment and performance of all obligations under this Agreement.</u><span style="font-weight:normal;">&nbsp;The PRINCIPAL BORROWER AND CO-BORROWER shall be liable for the entire obligation, and the LENDER may proceed against any one or all of them, either jointly or separately, at its option, without the necessity of exhausting remedies against the others or against any security. The obligations of each party shall remain in full force and effect notwithstanding any extension, restructuring, or modification of this Agreement, or any release, waiver, or impairment of any security or obligation of any other party.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="8" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:73.22pt; text-align:justify; widows:0; orphans:0; padding-left:2.78pt; font-family:'Libre Baskerville'; font-weight:bold;">NON-WAIVER<span style="font-weight:normal;">: No delay or failure on the part of the LENDER in the exercise of any right or remedy shall operate as a waiver thereof and no single or partial exercise by the LENDER of any right or remedy shall preclude other or further exercise thereof or the exercise of any other right or remedy. The PRINCIPAL BORROWER shall be in no way discharged from any other obligation or undertaking hereunder, should the LENDER compromise, extend or renew from time to time and for any period, whether or not longer than the original period, any obligation owed the LENDER by the</span><span style="font-weight:normal;">&nbsp;&nbsp;</span><span style="font-weight:normal;">PRINCIPAL BORROWER.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="9" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:63.44pt; text-align:justify; widows:0; orphans:0; padding-left:12.56pt; font-family:'Libre Baskerville'; font-weight:bold;">INTEGRATION &amp; AMENDMENT<span style="font-weight:normal;">: This Contract, including the attachments mentioned in the body as incorporated by reference, sets forth the entire agreement between the parties with regard to the subject matter hereof. Any amendment or modification of the terms and conditions of this Contract of Loan shall only be valid when made in a public instrument, signed by all parties, and attached to this original Contract of Loan.&nbsp;</span></li>
        </ol>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="10" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:58.3pt; text-align:justify; widows:0; orphans:0; padding-left:17.7pt; font-family:'Libre Baskerville'; font-weight:bold;">SUCCESSION<span style="font-weight:normal;">: This Loan will be binding upon the PRINCIPAL BORROWER their successors, permitted assigns, and heirs and shall inure to the benefit of the LENDER, its successors-in-interests and assigns. Provided however, the</span><span style="font-weight:normal;">&nbsp;&nbsp;</span><span style="font-weight:normal;">PRINCIPAL BORROWER shall not assign their rights or delegate their duties under the terms of this Loan without a written notice to and approval from the LENDER.</span></li>
        </ol>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="11" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:63.44pt; text-align:justify; widows:0; orphans:0; padding-left:12.56pt; font-family:'Libre Baskerville'; font-weight:bold;">VENUE &amp;<span style="font-weight:normal;">&nbsp;</span>JUDICIAL RELIEF<span style="font-weight:normal;">: Any conflict arising from the terms and condition of this Contract of Loan or non-payment of the obligation shall solely, exclusively and only, to the exclusion of all other courts, be filed with the proper courts of law in Barili, Cebu, Philippines.</span></li>
        </ol>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">In the event this Contract is referred to an attorney for collection, the PRINCIPAL BORROWER and CO-BORROWER shall indemnify the LENDER for attorney&rsquo;s fees and out-of-pocket expenses computed at five percent (5%) of the total amount due or One Hundred Thousand Pesos (Php. 100,000.00) , whichever is higher and Five Thousand Pesos (Php.5,000.00) appearance fee per hearing/setting, in addition to all other costs and damages which the court may award or entitle the LENDER.</span></p>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="12" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:68.59pt; text-align:justify; widows:0; orphans:0; padding-left:7.41pt; font-family:'Libre Baskerville'; font-weight:bold;">SEPARABILITY CLAUSE<span style="font-weight:normal;">: In the event that any of the provision of this Contract of Loan is held to be void, invalid or unenforceable, that provision shall be severed from the remainder of this Contract so as not to cause the invalidity or unenforceability of the remainder of this Contract. All remaining provisions of this Contract shall then continue in full force and effect. If any provision shall be deemed invalid due to its scope or breadth, such provision shall be deemed valid to the extent of the scope and breadth permitted by law.</span></li>
        </ol>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol start="13" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:73.74pt; text-align:justify; widows:0; orphans:0; padding-left:2.26pt; font-family:'Libre Baskerville'; font-weight:bold;">GOVERNING LAW<span style="font-weight:normal;">: This Contract of Loan shall be governed by and construed in accordance with Philippine Laws.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="14" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:73.1pt; text-align:justify; widows:0; orphans:0; padding-left:2.9pt; font-family:'Libre Baskerville'; font-weight:bold;">DATA PRIVACY. <span style="font-weight:normal;">By providing personal information and sensitive personal information, PRINCIPAL BORROWER and CO-BORROWER acknowledge and recognize the exclusive right of the LENDER to utilize the data for this Contract and for other relevant or incidental uses. The PRINCIPAL BORROWER and CO-BORROWER also acknowledge that all such information, records, files and among others, shall form part of the exclusive use of the LENDER and they consent to the use thereof. These acts of the LENDER are not and shall not be deemed as violation of data privacy law, human relations, or any breach of personal information or sensitive personal information. Consent hereof is likewise given when subsequent data and information are shared in the event of default, change of status, etc. The PRINCIPAL BORROWER and CO-BORROWER render the company, its officers, directions, stockholder, employees, agents and representatives free and harmless from any and all labilities from the use of said data, records or information, pursuant to R.A. 10173 otherwise known as the &ldquo;DATA PRIVACY ACT OF 2012&rdquo;.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="15" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:67.96pt; text-align:justify; widows:0; orphans:0; padding-left:8.04pt; font-family:'Libre Baskerville'; font-weight:bold;">AUTHORITY OF LENDER TO SECURE RELEVANT INFORMATION AND DOCUMENTS FROM DEVELOPMENT BANK OF THE PHILIPPINES, DepEd, CHED, GSIS, AND OTHER AGENCIES AND OFFICES:<span style="font-weight:normal;">&nbsp;The PRINCIPAL BORROWER and CO-BORROWER acknowledge the right of LENDER to make verifications to ensure their full and faithful compliance to this Contract, as such, the PRINCIPAL BORROWER and CO-BORROWER authorize, designate, constitute, and appoint LENDER or any of its authorized representative as their attorney-in-fact to REQUEST, SECURE, ACQUIRE, PROCURE, SUBMIT, PROCESS, FOLLOW-UP, CLAIM and RECEIVE any and all papers, information, records, and other documents from the Development Bank of the Philippines, GSIS, Department of Education, Commission on Higher Education, and other offices and agencies relevant to my afore-described ATM and UMID Cards, Salaries and Employment Benefits. BORROWERS expressly declare that this authority shall not in any way be construed as a violation of their rights under R.A. No. 1405, R.A. 10173, and other pertinent laws, rules and regulations, and circulars and hereby hold free and harmless DBP, DepEd, CHED, and GSIS relative to such disclosure.</span></li>
        </ol>
        <p style="margin-left:76pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:53.27pt; text-align:justify; padding-left:25.98pt; font-family:'Libre Baskerville'; font-weight:bold;">AUTHORITY TO ASSIGN TO COLLECTION AGENTS: <span style="font-weight:normal;">&nbsp;</span><span style="font-weight:normal;">PRINCIPAL BORROWER and CO-BORROWER expressly agree and authorize the LENDER to assign, endorse, or refer the collection of any unpaid outstanding obligation, including principal, interest, penalties and/or charges, to a third-party collection agency, at the sole discretion of the LENDER.</span></li>
        </ol>
        <p style="text-align:justify;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify;"><span style="font-family:'Libre Baskerville';">The PRINCIPAL BORROWER and CO-BORROWER further acknowledge that such assignment does not absolve the PRINCIPAL BORROWER and CO-BORROWER of any liability arising from or by reason of this Contract of Loan and all right rights and remedies the LENDER may exercise. The PRINCIPAL BORROWER and CO-BORROWER further consent to the disclosure of necessary personal information to such agency solely for the purpose of enforcing collection.</span></p>
        <p style="margin-left:76.25pt; text-align:justify;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:76.25pt; text-align:justify;"><span style="font-family:'Libre Baskerville';">All costs and expenses incurred by the LENDER and the agency shall be on account of the PRINCIPAL BORROWER and CO-BORROWER.</span></p>
        <p style="margin-left:76.25pt; text-align:justify;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <ol start="2" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:57.34pt; text-align:justify; padding-left:21.91pt; font-weight:bold;">AUTHORITY TO GARNISH: <span style="font-family:'Libre Baskerville'; font-weight:normal;">The PRINCIPAL BORROWER and CO-BORROWER agree, allow, and authorize the Development Bank of the Philippines, Rural Bank of the Philippines, Landbank of the Philippines, and all other banks which their accounts are held to garnish their accounts and funds deposited therein as a result of any writ of execution or other lawful Order/s by a court and other government offices, agencies and/or instrumentalities. The PRINCIPAL BORROWER and CO-BORROWER expressly declare that this authority shall not in any way be construed as a violation of their rights under R.A. No. 1405, R.A. 10173, and other pertinent laws, rules and regulations, and circulars and hereby hold free and harmless DBP, DepEd, CHED, and GSIS relative to such disclosure.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <ol start="3" style="margin:0pt; padding-left:0pt; list-style-type:upper-roman;">
            <li style="margin-left:63.56pt; text-align:justify; widows:0; orphans:0; padding-left:12.44pt; font-family:'Libre Baskerville'; font-weight:bold;">DECLARATION:<span style="font-weight:normal;">&nbsp;The PRINCIPAL BORROWER and CO-BORROWER finally declare that they have read this document and have fully understood its contents.</span><span style="font-weight:normal;">&nbsp;</span><span style="font-weight:normal;">&nbsp;They further declare that they voluntarily and willingly executed this Contract of Loan with full knowledge of their rights and obligations under the law.</span></li>
        </ol>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="margin-left:58pt; text-indent:-18pt; text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="widows:0; orphans:0;"><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span><strong><span style="font-family:'Libre Baskerville';">IN WITNESS WHEREOF</span></strong><span style="font-family:'Libre Baskerville';">, We have hereunto affixed our signatures this _____ day of ____________, 2026 at Poblacion, Barili, Cebu, Philippines.</span></p>
        <p style="widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">LENDER:</span></strong></p>
        <p style="text-align:center; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">INDOPACIFIC LENDING CORPORATION</span></strong></p>
        <p style="text-align:center; widows:0; orphans:0;"><em><span style="font-family:'Libre Baskerville';">Duly represented by:</span></em></p>
        <p style="widows:0; orphans:0;"><em><span style="font-family:'Libre Baskerville';">&nbsp;</span></em></p>
        <p style="text-align:center; widows:0; orphans:0;"><em><span style="font-family:'Libre Baskerville';">&nbsp;</span></em></p>
        <p style="text-align:center; widows:0; orphans:0;"><strong><u><span style="font-family:'Libre Baskerville';">RAVEN WYNDELL C. RICAPLAZA</span></u></strong></p>
        <p style="widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;</span></strong></p>
        <p style="widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">BORROWERS:</span></strong></p>
        <p style="text-align:center; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:center; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:center; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><span style="font-family:'Libre Baskerville';">&nbsp;</span></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="font-family:'Libre Baskerville';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></strong><strong><u><span style="font-family:'Libre Baskerville';">ANNABELLE S. RELLON</span></u></strong><strong><span style="width:25.34pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></strong><strong><span style="font-family:'Libre Baskerville';">&nbsp;&nbsp;&nbsp;&nbsp; </span></strong><strong><u><span style="font-family:'Libre Baskerville';">JHAIZE KLENT S. RELLON</span></u></strong></p>
        <p style="text-align:justify; widows:0; orphans:0;"><strong><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></strong><span style="font-family:'Libre Baskerville';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><em><span style="font-family:'Libre Baskerville';">Borrower</span></em><em><span style="width:26.83pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></em><em><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></em><em><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></em><em><span style="width:36pt; font-family:'Libre Baskerville'; display:inline-block;">&nbsp;</span></em><em><span style="font-family:'Libre Baskerville';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></em><em><span style="font-family:'Libre Baskerville';">&nbsp;</span></em><em><span style="font-family:'Libre Baskerville';">Borrower</span></em></p>
